const fs = require("fs");
const path = require("path");
const { pathToFileURL } = require("url");
const esbuild = require("esbuild");

function toCppModule(scriptContent) {
  const rawDelimiter = "SM_MAP_JS";
  return `// Auto-generated map injection script module
// DO NOT EDIT - This file is generated by scripts/generate-map-injection-cpp.js

module;

export module Extensions.InfinityNikki.Generated.MapInjectionScript;

import std;

export namespace Extensions::InfinityNikki::Generated {

constexpr std::wstring_view map_bridge_script = LR"${rawDelimiter}(${scriptContent})${rawDelimiter}";

}  // namespace Extensions::InfinityNikki::Generated
`;
}

async function main() {
  const projectRoot = path.resolve(__dirname, "..");
  const sourceEntry = path.join(
    projectRoot,
    "web",
    "src",
    "features",
    "map",
    "injection",
    "source",
    "index.js"
  );
  const generatedScriptDir = path.join(projectRoot, "scripts", "generated");
  const minifiedScriptPath = path.join(projectRoot, "scripts", "generated", "map_bridge.min.js");
  const generatedModulePath = path.join(
    projectRoot,
    "src",
    "extensions",
    "infinity_nikki",
    "generated",
    "map_injection_script.ixx"
  );

  if (!fs.existsSync(sourceEntry)) {
    throw new Error(`Map injection source entry not found: ${sourceEntry}`);
  }

  const sourceModule = await import(pathToFileURL(sourceEntry).href);
  if (typeof sourceModule.buildMapBridgeScriptTemplate !== "function") {
    throw new Error("buildMapBridgeScriptTemplate() is missing in injection source entry.");
  }

  const bridgeTemplate = sourceModule.buildMapBridgeScriptTemplate();
  const minified = esbuild.transformSync(bridgeTemplate, {
    loader: "js",
    minify: true,
  });

  fs.mkdirSync(generatedScriptDir, { recursive: true });
  fs.writeFileSync(minifiedScriptPath, minified.code, "utf8");
  console.log(
    `Generated minified map bridge script: ${path.relative(projectRoot, minifiedScriptPath)}`
  );

  const scriptContent = fs.readFileSync(minifiedScriptPath, "utf8").trim();
  fs.mkdirSync(path.dirname(generatedModulePath), { recursive: true });
  fs.writeFileSync(generatedModulePath, toCppModule(scriptContent), "utf8");

  console.log(
    `Generated C++ map injection module: ${path.relative(projectRoot, generatedModulePath)}`
  );
}

main().catch((error) => {
  const message = error instanceof Error ? error.message : String(error);
  console.error(`Error: ${message}`);
  process.exit(1);
});
